practice_tasks.solution:
def has_permission(allowed, user_roles):
    allowed_set = set(allowed)
    for role in user_roles:
        if role in allowed_set:
            return True
    return False

print(has_permission(['admin', 'editor'], ['viewer', 'editor']))

