import time

class RequestDedup:
    def __init__(self):
        self._seen = {}  # fingerprint -> timestamp

    def add(self, fingerprint):
        self._seen[fingerprint] = time.time()

    def is_duplicate(self, fingerprint):
        return fingerprint in self._seen

    def clear_older_than(self, cutoff):
        self._seen = {
            fp: ts for fp, ts in self._seen.items() if ts >= cutoff
        }

dedup = RequestDedup()
dedup.add('abc123')
dedup.add('def456')
print(dedup.is_duplicate('abc123'))
print(dedup.is_duplicate('xyz789'))
